// ค้นหารายการยืมที่ตรงกับ borrowId + สถานะ = ยืมอยู่
const allItems = $input.all();
const borrowId = $('Edit Fields - รับรหัสยืม').first().json.borrowId;

for (const item of allItems) {
  if (item.json['รหัสยืม'] === borrowId && item.json['สถานะ'] === 'ยืมอยู่') {
    return [{
      json: {
        found: true,
        รหัสยืม: item.json['รหัสยืม'],
        ชื่อผู้ยืม: item.json['ชื่อผู้ยืม'],
        Email: item.json['Email'],
        อุปกรณ์: item.json['อุปกรณ์'],
        'รหัสนศ.': item.json['รหัสนศ.'],
        วันที่ยืม: item.json['วันที่ยืม'],
        กำหนดคืน: item.json['กำหนดคืน'],
        สถานะ: item.json['สถานะ']
      }
    }];
  }
}

// ไม่พบรายการที่ตรงกัน
return [{ json: { found: false } }];

// หารายการที่เกินกำหนดคืน
const allItems = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const overdueItems = [];

for (const item of allItems) {
  const status = item.json['สถานะ'];
  const dueDate = item.json['กำหนดคืน'];

  if (status !== 'ยืมอยู่' || !dueDate || dueDate === '-') continue;

  const due = new Date(dueDate);
  due.setHours(0, 0, 0, 0);

  if (due < today) {
    overdueItems.push(item);
  }
}

if (overdueItems.length === 0) {
  // ไม่มีรายการเกินกำหนด — หยุด workflow
  return [];
}

return overdueItems;
